SELECT c.*, u.name AS user_name, u.profile_image_url AS user_profile_image_url
FROM comments c JOIN users u ON c.user_id = u.id
WHERE c.id = #{id}

SELECT c.*, u.name AS user_name, u.profile_image_url AS user_profile_image_url
FROM comments c JOIN users u ON c.user_id = u.id
WHERE c.post_id = #{postId} AND c.is_deleted = false
AND c.id > #{cursor}
ORDER BY c.created_at ASC
LIMIT #{size}
